            views: [
              { tradition: 'Particular (Limitada)', position: 'Cristo morreu especificamente e eficazmente para garantir a salvação dos eleitos.' },
              { tradition: 'Universal (Geral)', position: 'Cristo morreu por todos os homens, tornando a salvação disponível para quem crer.' },
              { tradition: 'Luterana', position: 'Expiação Universal com foco na promessa objetiva do Evangelho para todos.' }
            ]
